import { UNDEFINED, NULL } from '../../zc-constants';
import { defined, isUndefined } from '../../../utils/zcutils';

export function convertNull(val, options) {
    let { config, scale, columnKey } = options,
        { nullAs } = config;

    if (val === UNDEFINED) {
        val = NULL;
    }

    if (isUndefined(val) && defined(nullAs)) {
        if (nullAs === `{{min(${columnKey})}}`) {
            if (scale) {
                val = scale.domain()[0];
            }
        } else {
            val = nullAs;
        }
    }

    return val;
}
